observation.old_content:
lexer grammar SYsULexer;

// Keywords
Int : 'int';
Return : 'return';
While : 'while';
If : 'if';
Else : 'else';
Break : 'break';
Continue : 'continue';
Const : 'const';
Void : 'void';

// Punctuators
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';

Semi : ';';
Comma : ',';

// Operators
Plus : '+';
Minus : '-';
Star : '*';
Slash : '/';
Percent : '%';

Less : '<';
LessEqual : '<=';
Greater : '>';
GreaterEqual : '>=';

Equal : '=';
EqualEqual : '==';
Exclaim : '!';
ExclaimEqual : '!=';

AmpAmp : '&&';
PipePipe : '||';

// Bitwise operators
Amp : '&';
Pipe : '|';
Caret : '^';
Tilde : '~';

// Shift operators
LessLess : '<<';
GreaterGreater : '>>';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;


fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;


// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
    ;

Whitespace
    :   [ \t]+
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

